<script lang="ts">let{data}=$props();let status=$state('all');let visible=$derived(data.comments.filter((comment:any)=>status==='all'||comment.status===status));</script><svelte:head><title>评论管理｜暮色工作台</title></svelte:head><header class="studio-head"><div><p class="eyebrow">COMMENTS</p><h1>评论管理</h1><p>审核游客留言、处理提醒并隐藏不合适的内容。</p></div><div class="comment-filters"><button class:active={status==='all'} onclick={()=>status='all'}>全部</button><button class:active={status==='pending'} onclick={()=>status='pending'}>待审核</button><button class:active={status==='published'} onclick={()=>status='published'}>已展示</button></div></header><section class="studio-panel moderation-list">{#each visible as comment}<article class:unread={!comment.adminRead}><header><div><b>{comment.authorName}</b>{#if comment.mentionsAdmin}<span>@ 提醒我</span>{/if}{#if !comment.adminRead}<span>新评论</span>{/if}</div><time>{new Date(comment.createdAt).toLocaleString('zh-CN')}</time></header><a href={`/blog/${comment.postSlug}#comments`} target="_blank">评论于《{comment.postTitle}》↗</a><p>{comment.content}</p><footer>{#if comment.status!=='published'}<form method="POST" action="?/publish"><input type="hidden" name="id" value={comment.id}/><button class="primary small">通过并展示</button></form>{/if}{#if comment.status!=='hidden'}<form method="POST" action="?/hide"><input type="hidden" name="id" value={comment.id}/><button>隐藏</button></form>{/if}{#if !comment.adminRead}<form method="POST" action="?/read"><input type="hidden" name="id" value={comment.id}/><button>标为已读</button></form>{/if}<form method="POST" action="?/delete" onsubmit={(e)=>!confirm('永久删除这条评论？')&&e.preventDefault()}><input type="hidden" name="id" value={comment.id}/><button class="danger">删除</button></form><span>{comment.status==='pending'?'待审核':comment.status==='published'?'已展示':'已隐藏'}</span></footer></article>{:else}<div class="empty">没有符合条件的评论。</div>{/each}</section>
